class RecentCounter {
public:
    RecentCounter() {
        times = deque<int>();
    }

    int ping(int t) {
        times.push_back(t);
        while (times.front() < t - 3000) {
            times.pop_front();
        }
        return times.size();
    }

private:
    deque<int> times;
};
```
efficiency: HIGH
